// Compute axis bounds snugly around the active dataset.
// step  -> rounds bounds to a clean multiple (5 for index, 500 for HHI).
// mustInclude -> a value that must remain inside the rendered range
//                (e.g. propensity threshold 100, so the dashed line stays visible).
// Padding is the larger of (one step) and (8% of the data span).
function computeBounds(values, { step, mustInclude } = { step: 1, mustInclude: null }) {
  const vals = [...values];
  if (mustInclude != null) vals.push(mustInclude);
  const vmin = Math.min(...vals);
  const vmax = Math.max(...vals);
  const padding = Math.max(step, Math.ceil((vmax - vmin) * 0.08));
  return {
    min: Math.floor((vmin - padding) / step) * step,
    max: Math.ceil((vmax + padding) / step) * step,
  };
}

// Pick a "nice" step value targeting ~5-7 gridlines for the given data span.
// Used by tightBounds() below to choose readable HHI gridline spacing per dataset.
function pickNiceStep(span) {
  const target = span / 6;
  const niceSteps = [50, 100, 200, 500, 1000, 2000, 5000, 10000];
  return niceSteps.find(s => s >= target) || target;
}

// Tight linear-axis bounds for a numeric series. Filters out exact zeros
// (rows that represent "no activity" rather than a real low value), then
// snaps the min/max to a "nice" step. The floor sits ONE STEP below the
// data minimum (clamped at zero) so the lowest data point has breathing
// room from the chart edge rather than being pinned at the bottom. The
// top snaps to the next step above the data maximum.
// Used for the SOV chart HHI y-axis (always linear) and as a building
// block for the SOV x-axis below.
function tightBounds(values) {
  const filtered = values.filter(v => v > 0);
  if (!filtered.length) return { min: 0, max: 1, step: 1 };
  const vmin = Math.min(...filtered);
  const vmax = Math.max(...filtered);
  const span = vmax - vmin;
  const step = pickNiceStep(span);
  return {
    min: Math.max(0, Math.floor(vmin / step) * step - step),
    max: Math.ceil(vmax / step) * step,
    step,
  };
}

// Pick SOV x-axis configuration. Returns { min, max, useLog }.
// Per DD-018: use a log scale ONLY when the meaningful-value range spans
// more than ~1.5 orders of magnitude (e.g. Coinbase streaming 0.4%-42%
// gives a ratio of ~100, log triggers). Honda streaming (3%-10%, ratio
// ~3) and Honda linear (1%-19%, ratio ~15) both stay linear so the data
// doesn't cluster awkwardly. xMax is snapped to a nice cap ~15% above
// the observed max.
function pickSovAxis(values) {
  const meaningful = values.filter(v => v >= 0.1);
  const vmax = Math.max(...values, 1);
  const vmin = meaningful.length ? Math.min(...meaningful) : 0.5;
  const useLog = vmax / Math.max(vmin, 0.1) > 30;
  const niceCapsLinear = [5, 10, 12, 15, 20, 25, 30, 40, 50, 75, 100];
  const niceCapsLog    = [5, 10, 15, 20, 25, 30, 40, 50, 75, 100];
  const caps = useLog ? niceCapsLog : niceCapsLinear;
  const xMax = caps.find(c => c >= vmax * 1.15) || Math.ceil(vmax * 1.15);
  return { min: useLog ? 0.3 : 0, max: xMax, useLog };
}

const REACH_THRESHOLD = 4;
const PROPENSITY_THRESHOLD = 100;

const SAMBA_LOGO = "data:image/jpeg;base64,";
const HONDA_LOGO = "data:image/png;base64,";

function getTier(d, reachThreshold = REACH_THRESHOLD) {
  if (d.override_tier) return d.override_tier;
  // A bubble that sits exactly on the vertical share line is treated as "low share"
  // and falls into Content Affinity (if above index 100) or Supplemental (if below).
  // So the anchor / scale (high share) checks use strict > and the efficiency check uses <=.
  if (d.intender_pct >  reachThreshold && d.median_index > PROPENSITY_THRESHOLD) return "anchor";
  if (d.intender_pct <= reachThreshold && d.median_index > PROPENSITY_THRESHOLD) return "efficiency";
  if (d.intender_pct >  reachThreshold && d.median_index < PROPENSITY_THRESHOLD) return "scale";
  return "deprioritize";
}

const TIER_META = {
  anchor:      { label: "Primary Investment",  full: "High Share + High Propensity",  color: "#22c55e", bg: "rgba(34,197,94,0.08)",   rec: "Prioritize your media budget on these {unit}" },
  efficiency:  { label: "Efficiency Focus",    full: "Low Share + High Propensity",   color: "#3b82f6", bg: "rgba(59,130,246,0.08)",  rec: "Focus spend on smaller {unit} that resonate most with your audience" },
  scale:       { label: "Mass Reach",          full: "High Share + Low Propensity",   color: "#f59e0b", bg: "rgba(245,158,11,0.08)",  rec: "Invest for broad reach where your audience already spends most of their time" },
  deprioritize:{ label: "Supplemental",        full: "Low Share + Low Propensity",    color: "#94a3b8", bg: "rgba(148,163,184,0.08)", rec: "Consider after prioritizing other categories" },
};

const CustomTooltip = ({ active, payload, reachThreshold, viewMode }) => {
  if (!active || !payload?.length) return null;
  const d = payload[0].payload;
  const tier = getTier(d, reachThreshold);
  const meta = TIER_META[tier];
  const unit = viewMode === "linear" ? "networks" : "platforms";
  const rec = meta.rec.replace("{unit}", unit);
  return (
    <div style={{
      background: "#1a1a2e", border: `1px solid ${meta.color}`,
      borderRadius: 8, padding: "12px 16px", fontFamily: "'DM Sans', sans-serif",
      color: "#e2e8f0", fontSize: 13, lineHeight: 1.7, width: 240,
      boxShadow: "0 8px 32px rgba(0,0,0,0.4)"
    }}>
      <div style={{ fontWeight: 700, fontSize: 15, color: "#f8fafc", marginBottom: 4 }}>{d.app}</div>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 16 }}>
        <span style={{ color: "#94a3b8" }}>Share of Viewing Time</span>
        <span style={{ fontFamily: "JetBrains Mono", fontWeight: 500 }}>{d.intender_pct.toFixed(1)}%</span>
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 16 }}>
        <span style={{ color: "#94a3b8" }}>{viewMode === "linear" ? "Network Affinity" : "Platform Affinity"}</span>
        <span style={{ fontFamily: "JetBrains Mono", fontWeight: 500 }}>{d.median_index}</span>
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 16 }}>
        <span style={{ color: "#94a3b8" }}>Priority Score</span>
        <span style={{ fontFamily: "JetBrains Mono", fontWeight: 600 }}>{d.priority.toFixed(1)}</span>
      </div>
      <div style={{
        marginTop: 8, paddingTop: 8, borderTop: `1px solid ${meta.color}33`,
        color: meta.color, fontWeight: 600, fontSize: 12, lineHeight: 1.5
      }}>
        {meta.label}: {rec}
      </div>
    </div>
  );
};

const CustomDot = (props) => {
  const { cx, cy, payload, reachThreshold, maxPriority } = props;
  const tier = getTier(payload, reachThreshold);
  const color = TIER_META[tier].color;
  // Size encodes Priority Score (share x median index / 100) -- same approach as the SOV chart.
  // Range 7..28 mapped linearly from 0..maxPriority.
  const ratio = maxPriority > 0 ? Math.min(1, payload.priority / maxPriority) : 0;
  const r = 7 + ratio * 21;
  // Bubbles inside the average-range band (95-105 index) are rendered with reduced opacity
  // to visually signal "within average affinity" without dropping their tier identity.
  const inAvgBand = payload.median_index >= 95 && payload.median_index <= 105;
  const fillOpacity = inAvgBand ? 0.35 : 0.6;
  const strokeOpacity = inAvgBand ? 0.45 : 0.7;
  return (
    <circle cx={cx} cy={cy} r={r} fill={color} fillOpacity={fillOpacity} stroke={color} strokeOpacity={strokeOpacity} strokeWidth={0.75} />
  );
};

function TierCard({ tierKey, apps, viewMode }) {
  const meta = TIER_META[tierKey];
  const unit = viewMode === "linear" ? "networks" : "platforms";
  const rec = meta.rec.replace("{unit}", unit);
  return (
    <div style={{
      background: meta.bg, border: `1px solid ${meta.color}22`,
      borderRadius: 8, padding: "14px 18px", flex: "1 1 220px", minWidth: 220,
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
        <div style={{ width: 10, height: 10, borderRadius: "50%", background: meta.color }} />
        <span style={{ color: meta.color, fontWeight: 700, fontSize: 14 }}>{meta.label}</span>
      </div>
      <div style={{ fontSize: 11, color: "#94a3b8", marginBottom: 10, lineHeight: 1.5 }}>
        {meta.full}. {rec}.
      </div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
        {apps.map(a => (
          <span key={a} style={{
            fontSize: 11, padding: "2px 8px", borderRadius: 4,
            background: `${meta.color}15`, color: "#e2e8f0",
            border: `1px solid ${meta.color}22`, fontWeight: 500,
          }}>{a}</span>
        ))}
      </div>
    </div>
  );
}

