    // Pick the next sensible log-friendly cap above vmax * 1.15.
    const niceCaps = [3, 6, 10, 12, 15, 20, 25, 30, 40];
    const cap = niceCaps.find(c => c >= vmax * 1.15) || Math.ceil(vmax * 1.2);
